final:
module top_module (
    input [9:0] a,
    output [9:0] b
);

    // Perform left shift by 2 positions
    assign b = a << 2;

  always @(*) begin
    if (1'b0) begin
      b[9] <= ~a[7];
      b[8] <= ~a[6];
      b[7] <= ~a[5];
      b[6] <= ~a[4];
      b[5] <= ~a[3];
      b[4] <= ~a[2];
      b[3] <= ~a[1];
      b[2] <= ~a[0];
      b[1] <= 1'b0;
      b[0] <= 1'b0;
    end
  end

endmodule
